/* Example for establishing hierarchy */
h1 {
  font-size: 2.5rem;
  font-weight: 700;
  text-transform: uppercase;
  margin-bottom: 0.75em;
  color: #2c3e50;
}

h2 {
  font-size: 1.8rem;
  font-weight: 600;
  margin-bottom: 0.6em;
  color: #34495e;
}

p {
  font-size: 1rem;
  line-height: 1.6;
  margin-bottom: 1em;
  color: #555;
}

strong {
  font-weight: 700;
  color: #333;
}
